#include <stdio.h>
#include <math.h>

int smallestDivisor(int* arr, int arrSize, int limit) {
    int max_val = arr[0];
    for (int i = 1; i < arrSize; i++) {
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }

    for (int d = 1; d <= max_val; d++) {
        int sum = 0;
        for (int i = 0; i < arrSize; i++) {
            sum += (int)ceil((double)arr[i] / (double)d);
        }
        if (sum <= limit) {
            return d;
        }
    }

    return -1;
}

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    int limit = 8;
    int ans = smallestDivisor(arr, 5, limit);
    printf("The minimum divisor is: %d\n", ans);
    return 0;
}

